import $ from 'jquery';

class MainContainer {
    constructor() {
        this.link = $('.third a');
        this.arrow = $('.third a .fa');
        this.bounceArrow();
    }

    bounceArrow() {
        this.arrow.hover(function(){
            $(this).animate({
                top: '-10px',
                opacity: 0.5
            }, 500, function(){
                $(this).animate({
                    top: '0',
                    opacity: 1
                }, 500);
            });
        });
    }
}

export default MainContainer;